import { Column, Entity } from 'typeorm';

import { BaseEntity } from '../utils';

@Entity({
  name: 'country',
})
export class CountryEntity extends BaseEntity {
  @Column({
    name: 'name',
    type: 'varchar',
    length: 255,
    unique: true,
  })
  name: string;

  @Column({
    name: 'alpha_2',
    type: 'varchar',
    length: 2,
    unique: true,
  })
  alpha2: string;

  @Column({
    name: 'alpha_3',
    type: 'varchar',
    length: 3,
    unique: true,
    nullable: true,
  })
  alpha3: string | null;

  @Column({
    name: 'ioc',
    type: 'varchar',
    length: 3,
    unique: true,
    nullable: true,
  })
  ioc: string | null;

  @Column({
    name: 'currencies',
    type: 'varchar',
    array: true,
  })
  currencies: string[];

  @Column({
    name: 'languages',
    type: 'varchar',
    array: true,
  })
  languages: string[];

  @Column({
    name: 'calling_codes',
    type: 'varchar',
    array: true,
  })
  callingCodes: string[];

  @Column({
    name: 'enabled',
    type: 'boolean',
    default: true,
  })
  enabled: boolean;
}

